import axios from 'axios';

// Create axios instance
const api = axios.create({
  baseURL: 'http://localhost:5261/api',
  headers: {
    'Content-Type': 'application/json',
  },
  timeout: 30000,
});

// Request interceptor
api.interceptors.request.use(
  (config) => {
    console.log('📤 API Request:', config.method?.toUpperCase(), config.url);

    // Use sessionStorage (tab-specific) instead of localStorage
    const token = sessionStorage.getItem('token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    console.error('❌ Request error:', error);
    return Promise.reject(error);
  }
);

// Response interceptor
api.interceptors.response.use(
  (response) => {
    console.log('✅ API Response:', response.config.url, response.status);
    return response;
  },
  (error) => {
    console.error('❌ API Error:', error.message);

    if (error.response?.status === 401) {
      console.log('🔒 Unauthorized - Clearing auth data');
      sessionStorage.removeItem('token');
      sessionStorage.removeItem('user');
      window.location.href = '/';
    }

    return Promise.reject(error);
  }
);

// Auth Service
export const authService = {
  login: async (email, password) => {
    console.log('🔐 Attempting login:', email);
    const response = await api.post('/auth/login', { email, password });

    if (response.data.token) {
      // Store in sessionStorage (tab-specific)
      sessionStorage.setItem('token', response.data.token);
      sessionStorage.setItem('user', JSON.stringify(response.data));
      console.log('✅ Login successful, session data saved');
    }

    return response.data;
  },

  register: async (userData) => {
    console.log('📝 Attempting registration:', userData.email);
    const response = await api.post('/auth/register', userData);

    if (response.data.token) {
      sessionStorage.setItem('token', response.data.token);
      sessionStorage.setItem('user', JSON.stringify(response.data));
      console.log('✅ Registration successful, session data saved');
    }

    return response.data;
  },

  logout: () => {
    console.log('👋 Logging out from this tab');
    sessionStorage.removeItem('token');
    sessionStorage.removeItem('user');
  },

  getCurrentUser: () => {
    const userStr = sessionStorage.getItem('user');
    if (userStr) {
      try {
        return JSON.parse(userStr);
      } catch (e) {
        console.error('Error parsing user data:', e);
        return null;
      }
    }
    return null;
  },
};

// Admin Service
export const adminService = {
  getDashboard: () => api.get('/admin/dashboard'),
  getProducts: () => api.get('/admin/products'),
  createProduct: (data) => api.post('/admin/products', data),
  updateProduct: (id, data) => api.put(`/admin/products/${id}`, data),
  deleteProduct: (id) => api.delete(`/admin/products/${id}`),
  getSales: () => api.get('/admin/sales'),
  updateSaleStatus: (id, status) => api.put(`/admin/sales/${id}/status`, { status }),
};

// Partner Service
export const partnerService = {
  getDashboard: () => api.get('/partner/dashboard'),
  getProducts: () => api.get('/partner/products'),
  getBuyers: () => api.get('/partner/buyers'),
  getSales: () => api.get('/partner/sales'),
  createSale: (data) => api.post('/partner/sales', data),
  searchBuyers: (email) => api.get(`/partner/buyers/search?email=${email}`),
  canSellToBuyer: (productId, buyerId) => api.get(`/partner/products/${productId}/can-sell/${buyerId}`),
};

export default api;
